from fastapi import FastAPI, Header, HTTPException
from pydantic import BaseModel
import secrets

app = FastAPI()

shelters = {}
pets = {}
tokens = {}

shelter_counter = 0
pet_counter = 0


class SignupRequest(BaseModel):
    username: str
    password: str


class LoginRequest(BaseModel):
    username: str
    password: str


def get_current_shelter(authorization: str):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing token")
    token = authorization.replace("Bearer ", "").strip()
    shelter_id = tokens.get(token)
    if shelter_id is None:
        raise HTTPException(status_code=401, detail="Invalid token")
    return shelter_id


@app.post("/signup")
def signup(req: SignupRequest):
    global shelter_counter
    for s in shelters.values():
        if s["username"] == req.username:
            raise HTTPException(status_code=400, detail="Username taken")
    shelter_counter += 1
    shelters[shelter_counter] = {
        "id": shelter_counter,
        "username": req.username,
        "password": req.password,
        "role": "shelter",
        "is_admin": False,
    }
    return {"id": shelter_counter, "username": req.username}


@app.post("/login")
def login(req: LoginRequest):
    for s in shelters.values():
        if s["username"] == req.username and s["password"] == req.password:
            token = secrets.token_hex(16)
            tokens[token] = s["id"]
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")


@app.post("/pets")
def create_pet(pet: dict, authorization: str = Header(None)):
    global pet_counter
    shelter_id = get_current_shelter(authorization)
    pet_counter += 1
    record = dict(pet)
    record["id"] = pet_counter
    record["user_id"] = shelter_id
    pets[pet_counter] = record
    return record


@app.get("/pets/{pet_id}")
def get_pet(pet_id: int):
    pet = pets.get(pet_id)
    if pet is None:
        raise HTTPException(status_code=404, detail="Pet not found")
    return pet


@app.get("/shelters/{shelter_id}")
def get_shelter(shelter_id: int):
    shelter = shelters.get(shelter_id)
    if shelter is None:
        raise HTTPException(status_code=404, detail="Shelter not found")
    return shelter


@app.get("/pets")
def list_pets():
    return list(pets.values())

