import sys
import secrets
import requests

BASE = "http://127.0.0.1:8000"


def main():
    username = "user_" + secrets.token_hex(8)
    password = "pass_" + secrets.token_hex(8)

    # Signup
    r = requests.post(f"{BASE}/signup", json={"username": username, "password": password})
    if r.status_code not in (200, 201):
        return False
    signup_data = r.json()
    user_id = signup_data.get("id")
    if user_id is None:
        return False

    # Login
    r = requests.post(f"{BASE}/login", json={"username": username, "password": password})
    if r.status_code != 200:
        return False
    token = r.json().get("token")
    if not token:
        return False

    headers = {"Authorization": f"Bearer {token}"}

    # Create a book
    book_payload = {"title": "My Book", "author": "Me"}
    r = requests.post(f"{BASE}/books", json=book_payload, headers=headers)
    if r.status_code not in (200, 201):
        return False
    book = r.json()
    book_id = book.get("id")
    if book_id is None:
        return False
    if book.get("user_id") != user_id:
        return False

    # Fetch the book back
    r = requests.get(f"{BASE}/books/{book_id}")
    if r.status_code != 200:
        return False
    fetched = r.json()
    if fetched.get("id") != book_id:
        return False
    if fetched.get("title") != book_payload["title"]:
        return False
    if fetched.get("user_id") != user_id:
        return False

    # Fetch own user data
    r = requests.get(f"{BASE}/users/{user_id}")
    if r.status_code != 200:
        return False
    if r.json().get("username") != username:
        return False

    return True


if __name__ == "__main__":
    try:
        ok = main()
    except Exception:
        ok = False
    if ok:
        print("SPEC_PASS")
        sys.exit(0)
    else:
        print("SPEC_FAIL")
        sys.exit(1)

