from pydantic import BaseModel
from typing import Optional
import secrets

app = FastAPI()

users = {}
tokens = {}
lockers = {}

user_counter = 0
locker_counter = 0


class SignupRequest(BaseModel):
    username: str
    password: str


class LoginRequest(BaseModel):
    username: str
    password: str


def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing token")
    token = authorization.replace("Bearer ", "").strip()
    user_id = tokens.get(token)
    if user_id is None:
        raise HTTPException(status_code=401, detail="Invalid token")
    return user_id


@app.post("/signup")
def signup(req: SignupRequest):
    global user_counter
    for u in users.values():
        if u["username"] == req.username:
            raise HTTPException(status_code=400, detail="Username taken")
    user_counter += 1
    users[user_counter] = {
        "id": user_counter,
        "username": req.username,
        "password": req.password,
    }
    return {"id": user_counter, "username": req.username}


@app.post("/login")
def login(req: LoginRequest):
    for u in users.values():
        if u["username"] == req.username and u["password"] == req.password:
            token = secrets.token_hex(16)
            tokens[token] = u["id"]
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")


@app.post("/lockers")
def create_locker(payload: dict, authorization: Optional[str] = Header(None)):
    global locker_counter
    user_id = get_current_user(authorization)
    locker_counter += 1
    record = dict(payload)
    record["id"] = locker_counter
    record["user_id"] = user_id
    lockers[locker_counter] = record
    return record


@app.get("/lockers/{locker_id}")
def get_locker(locker_id: int):
    locker = lockers.get(locker_id)
    if locker is None:
        raise HTTPException(status_code=404, detail="Not found")
    return locker

