from fastapi import FastAPI, Header, HTTPException
from pydantic import BaseModel
from typing import Optional
import secrets

app = FastAPI()

users = {}
tokens = {}
claims = {}

user_counter = 0
claim_counter = 0


class SignupRequest(BaseModel):
    username: str
    password: str


class LoginRequest(BaseModel):
    username: str
    password: str


def get_user_from_token(authorization: Optional[str]):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing token")
    token = authorization.replace("Bearer ", "")
    user_id = tokens.get(token)
    if user_id is None:
        raise HTTPException(status_code=401, detail="Invalid token")
    return user_id


@app.post("/signup")
def signup(req: dict):
    global user_counter
    user_counter += 1
    username = req.get("username")
    for u in users.values():
        if u["username"] == username:
            raise HTTPException(status_code=400, detail="User exists")
    user = {
        "id": user_counter,
        "username": username,
        "password": req.get("password"),
        "role": req.get("role", "policyholder"),
    }
    user.update(req)
    user["id"] = user_counter
    users[user_counter] = user
    return {"id": user_counter, "username": username, "role": user["role"]}


@app.post("/login")
def login(req: LoginRequest):
    for uid, u in users.items():
        if u["username"] == req.username and u["password"] == req.password:
            token = secrets.token_hex(16)
            tokens[token] = uid
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")


@app.post("/claims")
def create_claim(claim: dict, authorization: Optional[str] = Header(None)):
    global claim_counter
    user_id = get_user_from_token(authorization)
    claim_counter += 1
    record = {
        "id": claim_counter,
        "user_id": user_id,
    }
    record.update(claim)
    record["id"] = claim_counter
    record["user_id"] = user_id
    claims[claim_counter] = record
    return record


@app.get("/claims/{claim_id}")
def get_claim(claim_id: int, authorization: Optional[str] = Header(None)):
    get_user_from_token(authorization)
    claim = claims.get(claim_id)
    if claim is None:
        raise HTTPException(status_code=404, detail="Claim not found")
    return claim


@app.get("/users/{user_id}")
def get_user(user_id: int):
    user = users.get(user_id)
    if user is None:
        raise HTTPException(status_code=404, detail="User not found")
    return user

