        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]


@app.post("/signup")
def signup(user: SignupUser):
    global user_counter
    user_counter += 1
    record = user.dict()
    record["id"] = user_counter
    users[user_counter] = record
    return {"id": user_counter, "username": user.username, "role": record["role"]}


@app.post("/login")
