    for uid, u in users.items():
        if u["username"] == creds.username and u["password"] == creds.password:
            token = f"token-{uid}-{creds.username}"
            tokens[token] = uid
            return {"token": token}
    raise HTTPException(status_code=401, detail="Bad credentials")


